    operator: TAccountMetas[3];
    claimStatus: TAccountMetas[4];
    node: TAccountMetas[5];
    stakingConfig: TAccountMetas[6];
    position: TAccountMetas[7];
    vault: TAccountMetas[8];
    treasury: TAccountMetas[9];
